#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char A[100005], B[100005];
        scanf("%s",A);
        scanf("%s",B);
        int cntA[26]={0}, cntB[26]={0};
        for(int i=0;i<N;i++) cntA[A[i]-'a']++;
        for(int i=0;i<N;i++) cntB[B[i]-'a']++;
        int ans=0;
        for(int i=0;i<26;i++){
            int m = cntA[i] < cntB[i] ? cntA[i] : cntB[i];
            if(m>ans) ans=m;
        }
        printf("%d\n",ans);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        string A,B; cin>>A>>B;
        int cntA[26]={0}, cntB[26]={0};
        for(char ch: A) cntA[ch-'a']++;
        for(char ch: B) cntB[ch-'a']++;
        int ans=0;
        for(int i=0;i<26;i++) ans = max(ans, min(cntA[i], cntB[i]));
        cout<<ans<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String A = br.readLine().trim();
            String B = br.readLine().trim();
            int[] cntA = new int[26];
            int[] cntB = new int[26];
            for (int i = 0; i < N; i++) cntA[A.charAt(i) - 'a']++;
            for (int i = 0; i < N; i++) cntB[B.charAt(i) - 'a']++;
            int ans = 0;
            for (int i = 0; i < 26; i++) ans = Math.max(ans, Math.min(cntA[i], cntB[i]));
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

